#!/usr/bin/env node
import { build } from "esbuild";

const production = process.env.NODE_ENV === "production";

await build({
  entryPoints: ["src/background/index.js"],
  outfile: "background.js",
  bundle: true,
  format: "iife",
  platform: "browser",
  target: ["chrome88", "safari15"],
  sourcemap: false,
  minify: production,
  legalComments: "none",
  banner: {
    js:
      "/* Generated by scripts/build-extension.mjs from src/background/index.js. " +
      "Do not edit background.js directly. */\n" +
      'importScripts("ExtPay.js");',
  },
  logLevel: "info",
});
